{action_set_definitions}: {
  "get_batch_details": {
    "description": "Retrieves the ledger information for a specific batch ID, including product name, current location, current status, and production timestamp.",
    "parameters": {
      "type": "object",
      "properties": {
        "batch_id": {
          "type": "string",
          "description": "The unique identifier for the food batch (e.g., 'CS-404')."
        }
      },
      "required": [
        "batch_id"
      ]
    },
    "example_output": {
      "batch_id": "CS-404",
      "product_name": "Creamy Caesar Dressing",
      "location": "Retail-North",
      "status": "active",
      "production_date": "2023-11-01 14:00:00"
    }
  },
  "trace_genealogy": {
    "description": "Traces the ingredients (upstream) or the products created from a batch (downstream).",
    "parameters": {
      "type": "object",
      "properties": {
        "batch_id": {
          "type": "string",
          "description": "The batch ID to trace from."
        },
        "direction": {
          "type": "string",
          "enum": [
            "upstream",
            "downstream"
          ],
          "description": "Direction of trace: 'upstream' for ingredients/raw materials, 'downstream' for finished goods/distributed lots."
        }
      },
      "required": [
        "batch_id",
        "direction"
      ]
    },
    "example_output": [
      {
        "batch_id": "ING-101",
        "product_name": "Liquid Egg"
      }
    ]
  },
  "get_inspection_records": {
    "description": "Queries lab results and quality control logs for a specific batch to identify pathogens or safety failures.",
    "parameters": {
      "type": "object",
      "properties": {
        "batch_id": {
          "type": "string",
          "description": "The batch ID to inspect."
        }
      },
      "required": [
        "batch_id"
      ]
    },
    "example_output": [
      {
        "test_type": "Listeria monocytogenes",
        "result": "Positive",
        "timestamp": "2023-11-01 10:00:00"
      }
    ]
  },
  "update_batch_status": {
    "description": "Updates the status of a specific batch in the ledger (e.g., to 'recalled' or 'quarantined').",
    "parameters": {
      "type": "object",
      "properties": {
        "batch_id": {
          "type": "string",
          "description": "The batch ID to update."
        },
        "new_status": {
          "type": "string",
          "description": "The target status (e.g., 'recalled')."
        }
      },
      "required": [
        "batch_id",
        "new_status"
      ]
    },
    "example_output": {
      "success": true,
      "updated_id": "CS-404"
    }
  },
  "update_recall_registry": {
    "description": "Adds a formal entry to the global recall registry detailing the root cause and all affected batches.",
    "parameters": {
      "type": "object",
      "properties": {
        "root_cause_batch_id": {
          "type": "string",
          "description": "The ID of the batch identified as the source of contamination."
        },
        "affected_batch_ids": {
          "type": "array",
          "items": {
            "type": "string"
          },
          "description": "A list of all contaminated finished goods batch IDs."
        },
        "reason": {
          "type": "string",
          "description": "Detailed explanation of the contamination and tracing logic."
        }
      },
